={
  "model": "{{ $env.CLAUDE_MODEL || 'claude-sonnet-4-6' }}",
  "max_tokens": 3000,
  "system": "You are a security-awareness trainer. For the given topic produce a SINGLE valid JSON object for a short awareness QUIZ plus a 'Spot the phish' exercise, for general non-technical staff. Keys: topic; intro (one sentence); questions (6-8 items, each {q, options (array of exactly 4 short strings), answer (0-based index of the correct option), why (one-sentence explanation)}); spotThePhish {scenario (one sentence), email {from, subject, lines (array of 3-5 short body lines)}, redFlags (3-5 short strings naming the give-aways in THIS email), verdict (one sentence)}. Engaging, plain language. Do NOT use markdown code fences. Output ONLY the JSON object.",
  "messages": [ {"role":"user","content": {{ JSON.stringify('Create an awareness quiz and spot-the-phish exercise for the topic: ' + ($json.topic || 'phishing')) }} } ]
}

