const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json;
return [{ json: { data: data, topic: r.topic, date: r.date, client: r.client, markdown: raw } }];

const d=$json.data||{}; const topic=$json.topic||'Security'; const date=$json.date||''; const client=($json.client||'').toString();
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
const byline = client? ('Prepared for '+client) : 'Security Awareness';
const Q=(d.questions||[]); const sp=d.spotThePhish||{}; const em=sp.email||{};
const letters=['A','B','C','D'];
function optList(q,showAns){ return '<ol class="opts">'+(q.options||[]).map(function(o,i){ var hit=(showAns && q.answer===i); return '<li'+(hit?' class="hit"':'')+'>'+esc(o)+(hit?' &#10003;':'')+'</li>'; }).join('')+'</ol>'; }
var emailCard='<div class="email"><div class="eh"><b>From:</b> '+esc(em.from||'')+'<br><b>Subject:</b> '+esc(em.subject||'')+'</div><div class="eb">'+((em.lines||[]).map(function(l){return '<p>'+esc(l)+'</p>';}).join(''))+'</div></div>';
var partQ=Q.map(function(q,i){ return '<div class="q"><div class="qn">'+(i+1)+'. '+esc(q.q)+'</div>'+optList(q,false)+'</div>'; }).join('');
var factQ=Q.map(function(q,i){ return '<div class="q"><div class="qn">'+(i+1)+'. '+esc(q.q)+'</div><div class="ans">Answer: '+(letters[q.answer]||'?')+' &mdash; '+esc((q.options||[])[q.answer]||'')+'</div><div class="why">'+esc(q.why||'')+'</div></div>'; }).join('');
var EXTRA=".opts{list-style:upper-alpha;margin:6px 0 0;padding-left:24px} .opts li{font-size:13.5px;line-height:1.5;margin:3px 0} .opts li.hit{color:#1E6B3A;font-weight:700} .q{margin:0 0 14px;page-break-inside:avoid} .qn{font-weight:700;font-size:14px;color:#0E2233} .ans{font-size:13px;color:#1E6B3A;font-weight:700;margin-top:4px} .why{font-size:12.5px;color:#5A6472} .email{border:1px solid #E2E6EC;border-radius:8px;overflow:hidden;margin:8px 0} .email .eh{background:#F3F6F8;padding:10px 14px;font-size:13px;color:#2b3340} .email .eb{padding:10px 14px} .email .eb p{margin:0 0 6px;font-size:13.5px} .rf{margin:8px 0;padding-left:20px} .rf li{font-size:13px;color:#8a1f1f;margin:4px 0}";
var CSS="@page{margin:0} *{box-sizing:border-box} body{margin:0;font-family:-apple-system,\"Segoe UI\",Arial,sans-serif;color:#11151c} .pg{padding:44px 52px;page-break-after:always} .pg:last-child{page-break-after:auto} .kick{color:#0E7C86;letter-spacing:2px;font-weight:800;font-size:12px;text-transform:uppercase} h1.t{font-family:Georgia,serif;font-size:30px;color:#0E2233;margin:6px 0 4px} .sub{color:#5A6472;font-size:13px;margin:0 0 18px} h2{font-family:Georgia,serif;font-size:19px;color:#0E2233;margin:20px 0 10px;border-bottom:2px solid #0E7C86;padding-bottom:6px} p{font-size:14px;line-height:1.6;color:#2b3340} .foot{position:fixed;bottom:22px;left:52px;right:52px;color:#9aa6b2;font-size:11px;border-top:1px solid #E2E6EC;padding-top:8px;display:flex;justify-content:space-between} .card{border:1px solid #E2E6EC;border-radius:8px;padding:14px 16px;margin:12px 0;page-break-inside:avoid} .card h3{margin:0 0 8px;font-family:Georgia,serif;font-size:16px;color:#0E2233} .pill{display:inline-block;background:#E6F4F1;color:#0E7C86;font-weight:800;font-size:11px;padding:3px 10px;border-radius:12px;letter-spacing:.5px}"+EXTRA;
var participant='<div class="pg"><div class="kick">Awareness Quiz · Participant</div><h1 class="t">'+esc(topic)+' — Quick Quiz</h1><div class="sub">'+esc(d.intro||'Test your knowledge.')+'</div>'+partQ+'<h2>Spot the Phish</h2><p>'+esc(sp.scenario||'Review the email below. How many warning signs can you spot?')+'</p>'+emailCard+'<div class="foot"><span>'+esc(byline)+'</span><span>'+esc(date)+'</span></div></div>';
var facilitator='<div class="pg"><div class="kick">Awareness Quiz · Facilitator key</div><h1 class="t">Answer Key</h1><div class="sub">'+esc(topic)+'</div>'+factQ+'<h2>Spot the Phish — Debrief</h2><p><b>Red flags:</b></p><ul class="rf">'+((sp.redFlags||[]).map(function(r){return '<li>'+esc(r)+'</li>';}).join(''))+'</ul><p><b>Verdict:</b> '+esc(sp.verdict||'')+'</p><div class="foot"><span>'+esc(byline)+' · AI-generated — review before use</span><span>'+esc(date)+'</span></div></div>';
const html='<!doctype html><html><head><meta charset="utf-8"><style>'+CSS+'</style></head><body>'+participant+facilitator+'</body></html>';
const fileSafe=topic.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'').slice(0,40)||'quiz';
return [{ json:{ html:html, topic:topic, date:date, fileSafe:fileSafe, outDir:'quiz', filePrefix:'quiz' } }];

const html = $json.html || '';
return [{ json: { topic:$json.topic, date:$json.date, fileSafe:$json.fileSafe, outDir:$json.outDir, filePrefix:$json.filePrefix },
  binary: { data: { data: Buffer.from(html,'utf8').toString('base64'), mimeType:'text/html', fileName:'index.html' } } }];

const fs = require('fs');
const meta = $('Render HTML').first().json;
const dir = '/reports/awareness/' + (meta.outDir || 'misc');
const name = (meta.filePrefix || 'asset') + '-' + (meta.fileSafe || 'item') + '-' + meta.date + '.pdf';
let buf = null;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (e) {}
try { fs.mkdirSync(dir, { recursive: true }); if (buf) fs.writeFileSync(dir + '/' + name, buf); } catch (e) {}
const out = { json: { ok: !!buf, file: dir + '/' + name, topic: meta.topic } };
try { const b = $input.first().binary; if (b && b.data) { b.data.fileName = name; out.binary = { data: b.data }; } } catch (e) {}
return [out];
